df_es_added &lt;- bldg_sfha |&gt;
  filter(pin10 %in% groups$group_T_A$pin10 | pin10 %in% groups$group_C_B$pin10 )|&gt;
 # filter(prelim_sfha_category %in% c("Added to prelim SFHA", "Never SFHA")) |&gt;
  mutate(pin_num = as.numeric(pin)) |&gt;
  dplyr::arrange(pin_num, sale_year, sale_date) |&gt;
  dplyr::group_by(pin_num, sale_year, pre_date_chr) |&gt;
  dplyr::slice_tail(n = 1) |&gt;
  dplyr::ungroup() |&gt;
  mutate(treated = prelim_sfha_category == "Added to prelim SFHA") |&gt; 

   group_by(pin_num) |&gt;
  mutate(
    g_add = if (any(addedto_prelim_sfha == 1, na.rm = TRUE)) {
      min(sale_year[addedto_prelim_sfha == 1], na.rm = TRUE)
    } else {
      0L
    }
  ) |&gt;
  ungroup()


added_counts &lt;- table(df_es_added$g_add, df_es_added$pre_date)



df_es_removed &lt;- bldg_sfha |&gt;
    filter(pin10 %in% groups$group_T_B$pin10 | pin10 %in% groups$group_C_D$pin10 )|&gt;

  #filter(prelim_sfha_category %in% c("Removed from prelim SFHA", "Always SFHA")) |&gt;
  mutate(pin_num = as.numeric(pin)) |&gt;
  dplyr::arrange(pin_num, sale_year, sale_date) |&gt;
  dplyr::group_by(pin_num, sale_year, pre_date_chr) |&gt;
  dplyr::slice_tail(n = 1) |&gt;
  dplyr::ungroup() |&gt;
  mutate(treated = prelim_sfha_category == "Removed from prelim SFHA") |&gt; 

   group_by(pin_num) |&gt;
  mutate(
    g_remove = if (any(removedfrom_prelim_sfha == TRUE, na.rm = TRUE)) {
      min(sale_year[removedfrom_prelim_sfha == TRUE], na.rm = TRUE)
    } else {
      0L
    }
  ) |&gt;
  ungroup()


removed_counts &lt;- table(df_es_removed$g_remove, df_es_removed$pre_date)



